    if (nullableInt.GetType() == typeof(int?))  // Always false
    {
        Console.WriteLine("This will never execute");
    }

    DateTime? nullableDate = DateTime.Now;

    // Noncompliant - redundant, will always be true if not null
    if (nullableDate.GetType() == typeof(DateTime))  // Always true when not null
    {
        Console.WriteLine("This will always execute when nullableDate has a value");
    }
}

