public void CheckTypes()
{
    int? nullableInt = 42;

    // Compliant - proper type checking
    if (nullableInt.HasValue && nullableInt.GetType() == typeof(int))
    {
        Console.WriteLine("Has a value and underlying type is int");
    }

    DateTime? nullableDate = DateTime.Now;

    // Compliant - check if it has a value
    if (nullableDate.HasValue)
    {
        Console.WriteLine($"Date value: {nullableDate.Value}");
    }

    // Compliant - pattern matching
    if (nullableInt is int value)
    {
        Console.WriteLine($"Integer value: {value}");
    }
}

public bool IsNullableInt(object obj)
{
    // Compliant - safe type checking
    return obj is int?;
}
